class Solution:
    def findMaxLength(self, nums):
        n = len(nums)
        pref = [0] * (n + 1)
        for i in range(n):
            pref[i + 1] = pref[i] + (1 if nums[i] == 1 else -1)
        best = 0
        for i in range(n + 1):
            for j in range(i + 1, n + 1):
                if pref[j] == pref[i]:
                    best = max(best, j - i)
        return best

