class Solution:
    def findMaxLength(self, nums):
        first = {0: -1}
        s = 0
        best = 0
        for i, v in enumerate(nums):
            s += 1 if v == 1 else -1
            if s in first:
                best = max(best, i - first[s])
            else:
                first[s] = i
        return best

