var findMaxLength = function(nums) {
    const first = new Map();
    first.set(0, -1);
    let s = 0, best = 0;
    for (let i = 0; i < nums.length; i++) {
        s += nums[i] === 1 ? 1 : -1;
        if (first.has(s)) {
            best = Math.max(best, i - first.get(s));
        } else {
            first.set(s, i);
        }
    }
    return best;
};
